            credentials.UserNameAuthentication.UserNamePasswordValidationMode = 
                UserNamePasswordValidationMode.Custom;
            credentials.UserNameAuthentication.Certificate = 
                new X509Certificate2("ServiceCert.pfx", "password");
            
            host.Description.Behaviors.Add(credentials);
            
            // Open the service
            host.Open();
            Console.WriteLine("Healthcare Record Service is running...");
            Console.WriteLine("Press <Enter> to stop the service.");
            Console.ReadLine();
            
            host.Close();
        }
